import requests

# Hypothetical API endpoint for Billboard charts
def get_chart_positions():
    api_url = "https://api.example.com/billboard/charts"
    params = {
        "song": "Amor Gitano",
        "chart_type": "Latin Pop Songs"
    }
    response = requests.get(api_url, params=params)
    if response.status_code == 200:
        data = response.json()
        print(f"Chart Position: {data['position']}")
    else:
        print("Failed to fetch chart data.")

get_chart_positions()
